/**
 * Generate Bitrix24 firewall config.
 *
 * Bitrix24 webhooks embed credentials in the URL path:
 *   https://{domain}.bitrix24.com/rest/{user_id}/{secret_code}/{method}.json
 *
 * Uses auth.base for URL rewriting — agent sends to a placeholder
 * host, mitmproxy rewrites to the real webhook URL.
 */

import { FIREWALL_PLACEHOLDER_HOST, writeOutput } from "./codegen";

const PLACEHOLDER_BASE = `https://${FIREWALL_PLACEHOLDER_HOST}/bitrix/hook`;

function generateTypeScript(): string {
  const lines: string[] = [
    "// Auto-generated firewall config for Bitrix24.",
    "// Webhook URL contains credentials in the path — uses auth.base for URL rewriting.",
    "// Regenerate: cd turbo && pnpm -F @vm0/firewalls-generator generate:bitrix",
    "//",
    "// DO NOT EDIT THIS FILE MANUALLY.",
    "",
    'import type { FirewallConfig } from "../firewall-types";',
    "",
    "export const bitrixFirewall = {",
    '  name: "bitrix",',
    '  description: "Bitrix24",',
    "  placeholders: {",
    `    BITRIX_WEBHOOK_URL: "${PLACEHOLDER_BASE}",`,
    "  },",
    "  apis: [",
    "    {",
    `      base: "${PLACEHOLDER_BASE}",`,
    "      auth: {",
    '        base: "${{ secrets.BITRIX_WEBHOOK_URL }}",',
    "      },",
    "      permissions: [],",
    "    },",
    "  ],",
    "} as const satisfies FirewallConfig;",
    "",
  ];

  return lines.join("\n");
}

export async function generate(): Promise<void> {
  console.error("Generating Bitrix24 firewall config...");
  const ts = generateTypeScript();
  writeOutput("bitrix", ts, import.meta.dirname);
}
